// ❌ BAD - lazy loading fires one SELECT per order in the loop, causing N+1
foreach (var order in ctx.Orders.ToList())
    Console.WriteLine(order.Customer.Name); // SELECT Customer WHERE Id=? each time

// ✅ GOOD - eager loading fetches everything in one JOIN query
var orders = await ctx.Orders
    .Include(o => o.Customer)
    .Include(o => o.Items)
    .AsNoTracking()
    .ToListAsync();

// Explicit loading for conditional case
var invoice = await ctx.Invoices.FindAsync(invoiceId);
if (needLineItems)
