// ❌ BAD - Singleton causes thread corruption and stale data across requests
builder.Services.AddSingleton<AppDbContext>();

// ✅ GOOD - Scoped (default): one context per request, disposed after
builder.Services.AddDbContext<AppDbContext>(opt =>
    opt.UseSqlServer(builder.Configuration.GetConnectionString("Default")));

// Background service pattern - create a scope per work item
public class OrderSyncWorker(IServiceScopeFactory factory) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken ct)
    {
        await using var scope = factory.CreateAsyncScope();
        var ctx = scope.ServiceProvider.GetRequiredService<AppDbContext>();
        await ctx.SaveChangesAsync(ct);
    }
}

// ❌ BAD - tracking 10,000 products makes DetectChanges O(n) per SaveChanges call
foreach (var product in ctx.Products.Where(p => p.CategoryId == 5).ToList())
    product.IsActive = false;
await ctx.SaveChangesAsync(); // DetectChanges scans all 10,000 tracked entities

// ✅ GOOD - set-based update bypasses the change tracker entirely
await ctx.Products
    .Where(p => p.CategoryId == 5)
    .ExecuteUpdateAsync(s => s.SetProperty(p => p.IsActive, false));
// Emits: UPDATE Products SET IsActive=0 WHERE CategoryId=5

// ❌ BAD - Update marks all columns Modified; missing DTO fields wipe existing data
var product = new Product { Id = productId, Price = newPrice }; // other fields are default
ctx.Update(product); // Name, Stock, Category etc. will be overwritten with defaults
await ctx.SaveChangesAsync();

// ✅ GOOD - Attach + set only changed properties for a surgical UPDATE
var product = new Product { Id = productId };
ctx.Attach(product);
product.Price = newPrice;
product.LastModifiedAt = DateTime.UtcNow;
await ctx.SaveChangesAsync();
// SQL: UPDATE Products SET Price=X, LastModifiedAt=Y WHERE Id=Z

// ❌ BAD - parallel Task.WhenAll on one context throws at runtime
var t1 = ctx.Orders.CountAsync();
var t2 = ctx.Customers.CountAsync();
await Task.WhenAll(t1, t2); // throws: second operation started before first completed

// ✅ GOOD - IDbContextFactory creates independent contexts for parallel work
public class DashboardService(IDbContextFactory<AppDbContext> factory)
{
    public async Task<(int orders, int customers)> GetCountsAsync()
    {
        await using var ctx1 = await factory.CreateDbContextAsync();
        await using var ctx2 = await factory.CreateDbContextAsync();
        var t1 = ctx1.Orders.CountAsync();
        var t2 = ctx2.Customers.CountAsync();
        await Task.WhenAll(t1, t2);
        return (t1.Result, t2.Result);
    }
}

// ❌ BAD - AsNoTracking with Include can create duplicate Product instances per OrderItem
var items = await ctx.OrderItems
    .Include(i => i.Product)
    .AsNoTracking()
    .ToListAsync(); // same Product row = multiple Product objects in memory

// ✅ GOOD - AsNoTrackingWithIdentityResolution deduplicates without change tracking
var items = await ctx.OrderItems
    .Include(i => i.Product)
    .AsNoTrackingWithIdentityResolution()
    .ToListAsync(); // same Product row = one Product object shared across items

// Identity map in action: second FindAsync does NOT hit the database
var p1 = await ctx.Products.FindAsync(101);
var p2 = await ctx.Products.FindAsync(101);
Console.WriteLine(ReferenceEquals(p1, p2)); // True

// ❌ BAD - SaveChanges inside a loop causes one transaction per item and is slow
foreach (var shipment in pendingShipments)
{
    shipment.Status = ShipmentStatus.Dispatched;
    await ctx.SaveChangesAsync(); // separate transaction per shipment
}

// ✅ GOOD - accumulate all changes then save once in one transaction
foreach (var shipment in pendingShipments)
    shipment.Status = ShipmentStatus.Dispatched;
await ctx.SaveChangesAsync(); // one transaction for all shipments

// Explicit transaction spanning two SaveChanges
await using var tx = await ctx.Database.BeginTransactionAsync();
await ctx.SaveChangesAsync();
await ctx.SaveChangesAsync();
await tx.CommitAsync();

// ❌ BAD - tracking query on a read-only endpoint wastes memory on snapshots
var invoices = await ctx.Invoices
    .Include(i => i.LineItems)
    .ToListAsync(); // all entities tracked with snapshots - never saved

// ✅ GOOD - no-tracking with identity resolution for read queries with Include
var invoices = await ctx.Invoices
    .Include(i => i.LineItems)
    .AsNoTrackingWithIdentityResolution()
    .ToListAsync();

// Write path: opt into tracking explicitly
var invoice = await ctx.Invoices.AsTracking().FirstAsync(i => i.Id == invoiceId);
invoice.Status = InvoiceStatus.Paid;
await ctx.SaveChangesAsync();
